package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseFileTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
    }

    @Test
    void testParseFileSuccess() throws Exception {
        // Mock FileInputStream construction to avoid actual file IO
        try (MockedConstruction<FileInputStream> mockedFileInputStream = Mockito.mockConstruction(FileInputStream.class)) {
            // Mock InputStreamReader construction to avoid actual IO
            try (MockedConstruction<InputStreamReader> mockedInputStreamReader = Mockito.mockConstruction(InputStreamReader.class,
                    (mock, context) -> {
                        // no-op
                    })) {
                CSVParser parser = CSVParser.parse(mockFile, charset, format);
                assertNotNull(parser);
                // Check internal state by reflection (format)
                var formatField = CSVParser.class.getDeclaredField("format");
                formatField.setAccessible(true);
                assertSame(format, formatField.get(parser));
            }
        }
    }

    @Test
    void testParseFileNullFile() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(null, charset, format));
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void testParseFileNullFormat() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockFile, charset, null));
        assertEquals("format", thrown.getMessage());
    }
}
